def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}

    locked = bool(s.get("locked", False))
    enrolled = bool(s.get("enrolled", False))
    max_attempts = int(s.get("max_attempts", 3))

    if name == "enroll":
        # Only an unlocked account that has not yet enrolled can register a factor.
        if not locked and not enrolled:
            s["enrolled"] = True
            s["factor"] = str(params.get("factor", "totp"))
            s["recovery_codes"] = int(params.get("recovery_codes", 10))
            s["verified"] = False
            s["failed_attempts"] = 0

    elif name == "challenge":
        # Present the enrolled factor; pass verifies, fail counts toward lockout.
        if enrolled and not locked:
            if bool(params.get("success", True)):
                s["verified"] = True
                s["failed_attempts"] = 0
            else:
                attempts = int(s.get("failed_attempts", 0)) + 1
                s["failed_attempts"] = attempts
                s["verified"] = False
                if attempts >= max_attempts:
                    s["locked"] = True

    elif name == "recover":
        # Spend a one-time backup code to unlock and re-verify access.
        if enrolled and int(s.get("recovery_codes", 0)) > 0:
            s["recovery_codes"] = int(s["recovery_codes"]) - 1
            s["locked"] = False
            s["failed_attempts"] = 0
            s["verified"] = True

    elif name == "lock":
        # Administratively lock the account; any verified session is dropped.
        s["locked"] = True
        s["verified"] = False

    return s

