def perceive(data):
    text = data if isinstance(data, str) else str(data.get("text", ""))
    out = {}
    for tok in text.replace(",", " ").split():
        if "=" not in tok:
            continue
        k, v = tok.split("=", 1)
        if k == "factor":
            out["factor"] = v
            out["enrolled"] = True
        elif k == "codes":
            try:
                out["recovery_codes"] = int(v)
            except ValueError:
                pass
    return out
